-- Create two test tables
CREATE TABLE archive_data (
  id INT PRIMARY KEY,
  content VARCHAR(100)
);

CREATE TABLE temp_data (
  id INT PRIMARY KEY,
  value VARCHAR(100)
);

INSERT INTO archive_data VALUES (1,'record A'),(2,'record B'),(3,'record C');
INSERT INTO temp_data VALUES (1,'temp 1'),(2,'temp 2'),(3,'temp 3');

SELECT 'archive_data' AS tbl, COUNT(*) AS rows FROM archive_data
UNION ALL
SELECT 'temp_data', COUNT(*) FROM temp_data;

-- TRUNCATE: remove all rows but keep the table structure
TRUNCATE TABLE temp_data;

SELECT COUNT(*) AS rows_after_truncate FROM temp_data;  -- should be 0

-- Can INSERT again after TRUNCATE
INSERT INTO temp_data VALUES (1,'new temp 1');
SELECT * FROM temp_data;

-- DROP: remove the table entirely (structure + data)
DROP TABLE archive_data;

-- This would now cause an error:
-- SELECT * FROM archive_data;  -- table does not exist

SELECT table_name FROM information_schema.tables
WHERE table_schema = 'public' AND table_name IN ('archive_data','temp_data');

CREATE TABLE categories (
  cat_id   INT PRIMARY KEY,
  cat_name VARCHAR(50)
);

CREATE TABLE items (
  item_id  INT PRIMARY KEY,
  name     VARCHAR(80),
  cat_id   INT,
  FOREIGN KEY (cat_id) REFERENCES categories(cat_id)
);

INSERT INTO categories VALUES (1,'Electronics'),(2,'Books'),(3,'Clothing');
INSERT INTO items VALUES (1,'Laptop',1),(2,'SQL Book',2),(3,'T-Shirt',3);

SELECT * FROM items JOIN categories ON items.cat_id = categories.cat_id;

-- This will FAIL because items references categories:
-- DROP TABLE categories;  -- ERROR: cannot drop table categories because other objects depend on it

-- Option A: Drop child table first, then parent
DROP TABLE items;
DROP TABLE categories;

-- Recreate to demonstrate Option B:
CREATE TABLE categories2 (cat_id INT PRIMARY KEY, cat_name VARCHAR(50));
CREATE TABLE items2 (item_id INT PRIMARY KEY, name VARCHAR(80), cat_id INT,
  FOREIGN KEY (cat_id) REFERENCES categories2(cat_id));
INSERT INTO categories2 VALUES (1,'Electronics'),(2,'Books');
INSERT INTO items2 VALUES (1,'Laptop',1),(2,'SQL Book',2);

-- Option B: DROP with CASCADE (drops items2 automatically)
DROP TABLE categories2 CASCADE;

-- Verify items2 is also dropped:
SELECT table_name FROM information_schema.tables
WHERE table_schema = 'public' AND table_name IN ('categories2','items2');

-- Safe cleanup script (idempotent — can be run multiple times)

-- IF EXISTS prevents errors if the table doesn't exist
DROP TABLE IF EXISTS orders_backup;
DROP TABLE IF EXISTS reports_temp;
DROP TABLE IF EXISTS sessions_cache;

-- Confirm no error even though tables never existed
SELECT 'Cleanup completed' AS status;

-- Now create and populate a table
CREATE TABLE orders_backup (
  backup_id   INT PRIMARY KEY,
  original_id INT,
  customer    VARCHAR(60),
  total       DECIMAL(8,2),
  backed_up_at TIMESTAMP DEFAULT NOW()
);

INSERT INTO orders_backup VALUES
  (1, 1001, 'Alice',  150.00, NOW()),
  (2, 1002, 'Bob',    200.00, NOW()),
  (3, 1003, 'Carol',   80.00, NOW());

SELECT * FROM orders_backup;

-- Run cleanup again — no error because IF EXISTS handles missing table
DROP TABLE IF EXISTS orders_backup;
DROP TABLE IF EXISTS reports_temp;

SELECT 'Second cleanup completed — no errors' AS status;
